SELECT ULHSKEY ,CTKEY ,#{ctkey} || ';' || 'CTKEY'||';'||CTKEY AS CTKEY_DESC ,OWKEY ,ICKEY ,LCKEY ,ULCKEY ,QTY ,ICUTKEY ,UOM ,#{ctkey} || ';' || 'ICUTTYPE'||';'||UOM AS UOM_DESC ,PRODUCTDATE ,EXPIREDATE ,IBCONFIRMDATE ,ATTRIBUTE1 ,ATTRIBUTE2 ,ATTRIBUTE3 ,ATTRIBUTE4 ,ATTRIBUTE5 ,PRODUCTLOT ,IFSTATUS ,#{ctkey} || ';' || 'IFSTATUS'||';'||IFSTATUS AS IFSTATUS_DESC ,IFMESSAGE ,INSERTDATE ,INSERTURKEY ,SEQ FROM TWORK_TEMP_IVUP WHERE CTKEY = #{ctkey}
AND ULHSKEY = #{ulhskey}
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
LIMIT #{pagingLimit} OFFSET (#{currentPage} - 1) * #{pagingLimit}

SELECT 	COUNT(*)  
  FROM 	TWORK_TEMP_IVUP
 WHERE	CTKEY = #{ctkey}


		AND	 ULHSKEY = #{ulhskey}



   			AND  #{SEARCH_CONDITION}

#{GRIDPAGING_ROWNUMTYPE_TOP} SELECT ULHSKEY ,CTKEY ,OWKEY ,ICKEY ,LCKEY ,ULCKEY ,QTY ,ICUTKEY ,UOM ,PRODUCTDATE ,EXPIREDATE ,IBCONFIRMDATE ,ATTRIBUTE1 ,ATTRIBUTE2 ,ATTRIBUTE3 ,ATTRIBUTE4 ,ATTRIBUTE5 ,PRODUCTLOT ,IFSTATUS ,IFMESSAGE ,INSERTDATE ,INSERTURKEY ,SEQ FROM TWORK_TEMP_IVUP WHERE CTKEY = #{ctkey} AND ULHSKEY = #{ulhskey}
